import http from '../http'
//产品管理


//产品

// 专利列表
export function mehordList(query: any) {
    return http.get('/jkyErp/mehord/list', query)
}

// 产品详细
export function getmehord(id: any) {
    return http.get('/jkyErp/mehord/' + id)
}
// 新增产品
export function addmehord(data: any) {
    return http.post('/jkyErp/mehord/add', data)
}

// 修改产品
export function edimehord(data: any) {
    return http.post('/jkyErp/mehord/edit', data)
}

// 删除产品
export function delmehord(teamId: number) {
    return http.post('/jkyErp/mehord/del',teamId)
}







